#include <stdio.h>
#include <stdbool.h>

bool canPartitionEqualSubset(int* numbers, int numbersCount) {
    int sum = 0;
    for (int i = 0; i < numbersCount; i++) {
        sum += numbers[i];
    }
    if (sum % 2 != 0) {
        return false;
    }
    int target = sum / 2;
    bool* dp = (bool*)malloc((target + 1) * sizeof(bool));
    dp[0] = true;
    for (int i = 1; i <= target; i++) {
        dp[i] = false;
    }
    for (int i = 0; i < numbersCount; i++) {
        for (int j = target; j >= numbers[i]; j--) {
            if (dp[j - numbers[i]]) {
                dp[j] = true;
            }
        }
    }
    bool result = dp[target];
    free(dp);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        int* numbers = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &numbers[i]);
        }
        bool result = canPartitionEqualSubset(numbers, N);
        printf("%s\n", result ? "true" : "false");
        free(numbers);
    }
    return 0;
}

